def are_anagrams(str1: str, str2: str) -> bool:
    clean_str1 = ''.join(c.lower() for c in str1 if not c.isspace())
    clean_str2 = ''.join(c.lower() for c in str2 if not c.isspace())
    return sorted(clean_str1) == sorted(clean_str2)

def longest_palindromic_substring(s: str) -> str:
    if not s:
        return ""

    start, max_length = 0, 1
    n = len(s)

    def expand_around_center(left: int, right: int) -> (int, int):
        while left >= 0 and right < n and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right - 1

    for i in range(n):
        # Check for odd length palindrome
        l1, r1 = expand_around_center(i, i)
        if r1 - l1 + 1 > max_length:
            start, max_length = l1, r1 - l1 + 1

        # Check for even length palindrome
        l2, r2 = expand_around_center(i, i + 1)
        if r2 - l2 + 1 > max_length:
            start, max_length = l2, r2 - l2 + 1

    return s[start:start + max_length]

def run_length_encoding(s: str) -> str:
    if not s:
        return ''
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            result.append(str(count))
            result.append(s[i - 1])
            count = 1
    result.append(str(count))
    result.append(s[-1])
    return ''.join(result)

def decode_run_length(encoded_str: str) -> str:
    decoded_str = ''
    count_str = ''
    for char in encoded_str:
        if char.isdigit():
            count_str += char
        else:
            decoded_str += char * int(count_str)
            count_str = ''
    return decoded_str

def is_match(s: str, p: str) -> bool:
    from functools import lru_cache

    @lru_cache(None)
    def match(i: int, j: int) -> bool:
        if j == len(p):
            return i == len(s)
        first_match = i < len(s) and p[j] in {s[i], '.'}
        if j + 1 < len(p) and p[j + 1] == '*':
            return match(i, j + 2) or (first_match and match(i + 1, j))
        else:
            return first_match and match(i + 1, j + 1)

    return match(0, 0)

def string_permutations_unique(s: str) -> list[str]:
    from itertools import permutations

    # Generate all permutations of the characters in the string
    perms = set(''.join(p) for p in permutations(s))
    return list(perms)

def roman_to_int(s: str) -> int:
    roman_map = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    for i in range(len(s)):
        value = roman_map[s[i]]
        if i + 1 < len(s) and roman_map[s[i + 1]] > value:
            total -= value
        else:
            total += value
    return total

def caesar_cipher(text: str, shift: int, encode: bool) -> str:
    if not encode:
        shift = -shift
    result = []

    for char in text:
        if char.isalpha():
            base = ord('A') if char.isupper() else ord('a')
            shifted_char = chr((ord(char) - base + shift) % 26 + base)
            result.append(shifted_char)
        else:
            result.append(char)

    return ''.join(result)
